75: /**
76:  * The background thread that handles the sending of produce requests to the Kafka cluster. This thread makes metadata
77:  * requests to renew its view of the cluster and then sends produce requests to the appropriate nodes.
78:  */
79: public class Sender implements Runnable {
80: 
81:     private final Logger log;
82: 
83:     /* the state of each nodes connection */
84:     private final KafkaClient client;
85: 
86:     /* the record accumulator that batches records */
87:     private final RecordAccumulator accumulator;
88: 
89:     /* the metadata for the client */
90:     private final ProducerMetadata metadata;
91: 
92:     /* the flag indicating whether the producer should guarantee the message order on the broker or not. */
93:     private final boolean guaranteeMessageOrder;
94: 
95:     /* the maximum request size to attempt to send to the server */
96:     private final int maxRequestSize;
97: 
98:     /* the number of acknowledgements to request from the server */
99:     private final short acks;
100: 
101:     /* the number of times to retry a failed request before giving up */
102:     private final int retries;
103: 
104:     /* the clock instance used for getting the time */
105:     private final Time time;
106: 
107:     /* true while the sender thread is still running */
108:     private volatile boolean running;
109: 
110:     /* true when the caller wants to ignore all unsent/inflight messages and force close.  */
111:     private volatile boolean forceClose;
112: 
113:     /* metrics */
114:     private final SenderMetrics sensors;
115: 
116:     /* the max time to wait for the server to respond to the request*/
117:     private final int requestTimeoutMs;
118: 
119:     /* The max time to wait before retrying a request which has failed */
120:     private final long retryBackoffMs;
121: 
122:     /* all the state related to transactions, in particular the producer id, producer epoch, and sequence numbers */
123:     private final TransactionManager transactionManager;
124: 
125:     // A per-partition queue of batches ordered by creation time for tracking the in-flight batches
126:     private final Map<TopicPartition, List<ProducerBatch>> inFlightBatches;
127: 
128:     public Sender(LogContext logContext,
129:                   KafkaClient client,
130:                   ProducerMetadata metadata,
131:                   RecordAccumulator accumulator,
132:                   boolean guaranteeMessageOrder,
133:                   int maxRequestSize,
134:                   short acks,
135:                   int retries,
136:                   SenderMetricsRegistry metricsRegistry,
137:                   Time time,
138:                   int requestTimeoutMs,
139:                   long retryBackoffMs,
140:                   TransactionManager transactionManager) {
141:         this.log = logContext.logger(Sender.class);
142:         this.client = client;
143:         this.accumulator = accumulator;
144:         this.metadata = metadata;
145:         this.guaranteeMessageOrder = guaranteeMessageOrder;
146:         this.maxRequestSize = maxRequestSize;
147:         this.running = true;
148:         this.acks = acks;
149:         this.retries = retries;
150:         this.time = time;
151:         this.sensors = new SenderMetrics(metricsRegistry, metadata, client, time);
152:         this.requestTimeoutMs = requestTimeoutMs;
153:         this.retryBackoffMs = retryBackoffMs;
154:         this.transactionManager = transactionManager;
155:         this.inFlightBatches = new HashMap<>();
156:     }
157: 
158:     public List<ProducerBatch> inFlightBatches(TopicPartition tp) {
159:         return inFlightBatches.containsKey(tp) ? inFlightBatches.get(tp) : new ArrayList<>();
160:     }
161: 
162:     private void maybeRemoveFromInflightBatches(ProducerBatch batch) {
163:         List<ProducerBatch> batches = inFlightBatches.get(batch.topicPartition);
164:         if (batches != null) {
165:             batches.remove(batch);
166:             if (batches.isEmpty()) {
167:                 inFlightBatches.remove(batch.topicPartition);
168:             }
169:         }
170:     }
171: 
172:     private void maybeRemoveAndDeallocateBatch(ProducerBatch batch) {
173:         maybeRemoveFromInflightBatches(batch);
174:         this.accumulator.deallocate(batch);
175:     }
176: 
177:     /**
178:      *  Get the in-flight batches that has reached delivery timeout.
179:      */
180:     private List<ProducerBatch> getExpiredInflightBatches(long now) {
181:         List<ProducerBatch> expiredBatches = new ArrayList<>();
182: 
183:         for (Iterator<Map.Entry<TopicPartition, List<ProducerBatch>>> batchIt = inFlightBatches.entrySet().iterator(); batchIt.hasNext();) {
184:             Map.Entry<TopicPartition, List<ProducerBatch>> entry = batchIt.next();
185:             List<ProducerBatch> partitionInFlightBatches = entry.getValue();
186:             if (partitionInFlightBatches != null) {
187:                 Iterator<ProducerBatch> iter = partitionInFlightBatches.iterator();
188:                 while (iter.hasNext()) {
189:                     ProducerBatch batch = iter.next();
190:                     if (batch.hasReachedDeliveryTimeout(accumulator.getDeliveryTimeoutMs(), now)) {
191:                         iter.remove();
192:                         // expireBatches is called in Sender.sendProducerData, before client.poll.
193:                         // The !batch.isDone() invariant should always hold. An IllegalStateException
194:                         // exception will be thrown if the invariant is violated.
195:                         if (!batch.isDone()) {
196:                             expiredBatches.add(batch);
197:                         } else {
198:                             throw new IllegalStateException(batch.topicPartition + " batch created at " +
199:                                 batch.createdMs + " gets unexpected final state " + batch.finalState());
200:                         }
201:                     } else {
202:                         accumulator.maybeUpdateNextBatchExpiryTime(batch);
203:                         break;
204:                     }
205:                 }
206:                 if (partitionInFlightBatches.isEmpty()) {
207:                     batchIt.remove();
208:                 }
209:             }
210:         }
211:         return expiredBatches;
212:     }
213: 
214:     private void addToInflightBatches(List<ProducerBatch> batches) {
215:         for (ProducerBatch batch : batches) {
216:             List<ProducerBatch> inflightBatchList = inFlightBatches.computeIfAbsent(batch.topicPartition,
217:                 k -> new ArrayList<>());
218:             inflightBatchList.add(batch);
219:         }
220:     }
221: 
222:     public void addToInflightBatches(Map<Integer, List<ProducerBatch>> batches) {
223:         for (List<ProducerBatch> batchList : batches.values()) {
224:             addToInflightBatches(batchList);
225:         }
226:     }
227: 
228:     private boolean hasPendingTransactionalRequests() {
229:         return transactionManager != null && transactionManager.hasPendingRequests() && transactionManager.hasOngoingTransaction();
230:     }
231: 
232:     /**
233:      * The main run loop for the sender thread
234:      */
235:     @Override
236:     public void run() {
237:         log.debug("Starting Kafka producer I/O thread.");
238: 
239:         // main loop, runs until close is called
240:         while (running) {
241:             try {
242:                 runOnce();
243:             } catch (Exception e) {
244:                 log.error("Uncaught error in kafka producer I/O thread: ", e);
245:             }
246:         }
247: 
248:         log.debug("Beginning shutdown of Kafka producer I/O thread, sending remaining records.");
249: 
250:         // okay we stopped accepting requests but there may still be
251:         // requests in the transaction manager, accumulator or waiting for acknowledgment,
252:         // wait until these are completed.
253:         while (!forceClose && ((this.accumulator.hasUndrained() || this.client.inFlightRequestCount() > 0) || hasPendingTransactionalRequests())) {
254:             try {
255:                 runOnce();
256:             } catch (Exception e) {
257:                 log.error("Uncaught error in kafka producer I/O thread: ", e);
258:             }
259:         }
260: 
261:         // Abort the transaction if any commit or abort didn't go through the transaction manager's queue
262:         while (!forceClose && transactionManager != null && transactionManager.hasOngoingTransaction()) {
263:             if (!transactionManager.isCompleting()) {
264:                 log.info("Aborting incomplete transaction due to shutdown");
265:                 try {
266:                     // It is possible for the transaction manager to throw errors when aborting. Catch these
267:                     // so as not to interfere with the rest of the shutdown logic.
268:                     transactionManager.beginAbort();
269:                 } catch (Exception e) {
270:                     log.error("Error in kafka producer I/O thread while aborting transaction when during closing: ", e);
271:                     // Force close in case the transactionManager is in error states.
272:                     forceClose = true;
273:                 }
274:             }
275:             try {
276:                 runOnce();
277:             } catch (Exception e) {
278:                 log.error("Uncaught error in kafka producer I/O thread: ", e);
279:             }
280:         }
281: 
282:         if (forceClose) {
283:             // We need to fail all the incomplete transactional requests and batches and wake up the threads waiting on
284:             // the futures.
285:             if (transactionManager != null) {
286:                 log.debug("Aborting incomplete transactional requests due to forced shutdown");
287:                 transactionManager.close();
288:             }
289:             log.debug("Aborting incomplete batches due to forced shutdown");
290:             this.accumulator.abortIncompleteBatches();
291:         }
292:         try {
293:             this.client.close();
294:         } catch (Exception e) {
295:             log.error("Failed to close network client", e);
296:         }
297: 
298:         log.debug("Shutdown of Kafka producer I/O thread has completed.");
299:     }
300: 
301:     /**
302:      * Run a single iteration of sending
303:      *
304:      */
305:     void runOnce() {
306:         if (transactionManager != null) {
307:             try {
308:                 transactionManager.maybeResolveSequences();
309: 
310:                 RuntimeException lastError = transactionManager.lastError();
311: 
312:                 // do not continue sending if the transaction manager is in a failed state
313:                 if (transactionManager.hasFatalError()) {
314:                     if (lastError != null)
315:                         maybeAbortBatches(lastError);
316:                     client.poll(retryBackoffMs, time.milliseconds());
317:                     return;
318:                 }
319: 
320:                 if (transactionManager.hasAbortableError() && shouldHandleAuthorizationError(lastError)) {
321:                     return;
322:                 }
323: 
324:                 // Check whether we need a new producerId. If so, we will enqueue an InitProducerId
325:                 // request which will be sent below
326:                 transactionManager.bumpIdempotentEpochAndResetIdIfNeeded();
327: 
328:                 if (maybeSendAndPollTransactionalRequest()) {
329:                     return;
330:                 }
331:             } catch (AuthenticationException e) {
332:                 // This is already logged as error, but propagated here to perform any clean ups.
333:                 log.trace("Authentication exception while processing transactional request", e);
334:                 transactionManager.authenticationFailed(e);
335:             }
336:         }
337: 
338:         long currentTimeMs = time.milliseconds();
339:         long pollTimeout = sendProducerData(currentTimeMs);
340:         client.poll(pollTimeout, currentTimeMs);
341:     }
342: 
343:     // We handle {@code TransactionalIdAuthorizationException} and {@code ClusterAuthorizationException} by first
344:     // failing the inflight requests, then transition the state to UNINITIALIZED so that the user doesn't need to
345:     // instantiate the producer again.
346:     private boolean shouldHandleAuthorizationError(RuntimeException exception) {
347:         if (exception instanceof TransactionalIdAuthorizationException ||
348:                         exception instanceof ClusterAuthorizationException) {
349:             transactionManager.failPendingRequests(new AuthenticationException(exception));
350:             maybeAbortBatches(exception);
351:             transactionManager.transitionToUninitialized(exception);
352:             return true;
353:         }
354:         return false;
355:     }
356: 
357:     private long sendProducerData(long now) {
358:         MetadataSnapshot metadataSnapshot = metadata.fetchMetadataSnapshot();
359:         // get the list of partitions with data ready to send
360:         RecordAccumulator.ReadyCheckResult result = this.accumulator.ready(metadataSnapshot, now);
361: 
362:         // if there are any partitions whose leaders are not known yet, force metadata update
363:         if (!result.unknownLeaderTopics.isEmpty()) {
364:             // The set of topics with unknown leader contains topics with leader election pending as well as
365:             // topics which may have expired. Add the topic again to metadata to ensure it is included
366:             // and request metadata update, since there are messages to send to the topic.
367:             for (String topic : result.unknownLeaderTopics)
368:                 this.metadata.add(topic, now);
369: 
370:             log.debug("Requesting metadata update due to unknown leader topics from the batched records: {}",
371:                 result.unknownLeaderTopics);
372:             this.metadata.requestUpdate(false);
373:         }
374: 
375:         // remove any nodes we aren't ready to send to
376:         Iterator<Node> iter = result.readyNodes.iterator();
377:         long notReadyTimeout = Long.MAX_VALUE;
378:         while (iter.hasNext()) {
379:             Node node = iter.next();
380:             if (!this.client.ready(node, now)) {
381:                 // Update just the readyTimeMs of the latency stats, so that it moves forward
382:                 // every time the batch is ready (then the difference between readyTimeMs and
383:                 // drainTimeMs would represent how long data is waiting for the node).
384:                 this.accumulator.updateNodeLatencyStats(node.id(), now, false);
385:                 iter.remove();
386:                 notReadyTimeout = Math.min(notReadyTimeout, this.client.pollDelayMs(node, now));
387:             } else {
388:                 // Update both readyTimeMs and drainTimeMs, this would "reset" the node
389:                 // latency.
390:                 this.accumulator.updateNodeLatencyStats(node.id(), now, true);
391:             }
392:         }
393: 
394:         // create produce requests
395:         Map<Integer, List<ProducerBatch>> batches = this.accumulator.drain(metadataSnapshot, result.readyNodes, this.maxRequestSize, now);
396:         addToInflightBatches(batches);
397:         if (guaranteeMessageOrder) {
398:             // Mute all the partitions drained
399:             for (List<ProducerBatch> batchList : batches.values()) {
400:                 for (ProducerBatch batch : batchList)
401:                     this.accumulator.mutePartition(batch.topicPartition);
402:             }
403:         }
404: 
405:         accumulator.resetNextBatchExpiryTime();
406:         List<ProducerBatch> expiredInflightBatches = getExpiredInflightBatches(now);
407:         List<ProducerBatch> expiredBatches = this.accumulator.expiredBatches(now);
408:         expiredBatches.addAll(expiredInflightBatches);
409: 
410:         // Reset the producer id if an expired batch has previously been sent to the broker. Also update the metrics
411:         // for expired batches. see the documentation of @TransactionState.resetIdempotentProducerId to understand why
412:         // we need to reset the producer id here.
413:         if (!expiredBatches.isEmpty())
414:             log.trace("Expired {} batches in accumulator", expiredBatches.size());
415:         for (ProducerBatch expiredBatch : expiredBatches) {
416:             String errorMessage = "Expiring " + expiredBatch.recordCount + " record(s) for " + expiredBatch.topicPartition
417:                 + ":" + (now - expiredBatch.createdMs) + " ms has passed since batch creation";
418:             failBatch(expiredBatch, new TimeoutException(errorMessage), false);
419:             if (transactionManager != null && expiredBatch.inRetry()) {
420:                 // This ensures that no new batches are drained until the current in flight batches are fully resolved.
421:                 transactionManager.markSequenceUnresolved(expiredBatch);
422:             }
423:         }
424:         sensors.updateProduceRequestMetrics(batches);
425: 
426:         // If we have any nodes that are ready to send + have sendable data, poll with 0 timeout so this can immediately
427:         // loop and try sending more data. Otherwise, the timeout will be the smaller value between next batch expiry
428:         // time, and the delay time for checking data availability. Note that the nodes may have data that isn't yet
429:         // sendable due to lingering, backing off, etc. This specifically does not include nodes with sendable data
430:         // that aren't ready to send since they would cause busy looping.
431:         long pollTimeout = Math.min(result.nextReadyCheckDelayMs, notReadyTimeout);
432:         pollTimeout = Math.min(pollTimeout, this.accumulator.nextExpiryTimeMs() - now);
433:         pollTimeout = Math.max(pollTimeout, 0);
434:         if (!result.readyNodes.isEmpty()) {
435:             log.trace("Nodes with data ready to send: {}", result.readyNodes);
436:             // if some partitions are already ready to be sent, the select time would be 0;
437:             // otherwise if some partition already has some data accumulated but not ready yet,
438:             // the select time will be the time difference between now and its linger expiry time;
439:             // otherwise the select time will be the time difference between now and the metadata expiry time;
440:             pollTimeout = 0;
441:         }
442:         sendProduceRequests(batches, now);
443:         return pollTimeout;
444:     }
445: 
446:     /**
447:      * Returns true if a transactional request is sent or polled, or if a FindCoordinator request is enqueued
448:      */
449:     private boolean maybeSendAndPollTransactionalRequest() {
450:         if (transactionManager.hasInFlightRequest()) {
451:             // as long as there are outstanding transactional requests, we simply wait for them to return
452:             client.poll(retryBackoffMs, time.milliseconds());
453:             return true;
454:         }
455: 
456:         if (transactionManager.hasAbortableError()) {
457:             accumulator.abortUndrainedBatches(transactionManager.lastError());
458:         } else if (transactionManager.isAborting()) {
459:             accumulator.abortUndrainedBatches(new TransactionAbortedException());
460:         }
461: 
462:         TransactionManager.TxnRequestHandler nextRequestHandler = transactionManager.nextRequest(accumulator.hasIncomplete());
463:         if (nextRequestHandler == null)
464:             return false;
465: 
466:         AbstractRequest.Builder<?> requestBuilder = nextRequestHandler.requestBuilder();
467:         Node targetNode = null;
468:         try {
469:             FindCoordinatorRequest.CoordinatorType coordinatorType = nextRequestHandler.coordinatorType();
470:             targetNode = coordinatorType != null ?
471:                     transactionManager.coordinator(coordinatorType) :
472:                     client.leastLoadedNode(time.milliseconds()).node();
473:             if (targetNode != null) {
474:                 if (!awaitNodeReady(targetNode, coordinatorType)) {
475:                     log.trace("Target node {} not ready within request timeout, will retry when node is ready.", targetNode);
476:                     maybeFindCoordinatorAndRetry(nextRequestHandler);
477:                     return true;
478:                 }
479:             } else if (coordinatorType != null) {
480:                 log.trace("Coordinator not known for {}, will retry {} after finding coordinator.", coordinatorType, requestBuilder.apiKey());
481:                 maybeFindCoordinatorAndRetry(nextRequestHandler);
482:                 return true;
483:             } else {
484:                 log.trace("No nodes available to send requests, will poll and retry when until a node is ready.");
485:                 transactionManager.retry(nextRequestHandler);
486:                 client.poll(retryBackoffMs, time.milliseconds());
487:                 return true;
488:             }
489: 
490:             if (nextRequestHandler.isRetry())
491:                 time.sleep(nextRequestHandler.retryBackoffMs());
492: 
493:             long currentTimeMs = time.milliseconds();
494:             ClientRequest clientRequest = client.newClientRequest(targetNode.idString(), requestBuilder, currentTimeMs,
495:                 true, requestTimeoutMs, nextRequestHandler);
496:             log.debug("Sending transactional request {} to node {} with correlation ID {}", requestBuilder, targetNode, clientRequest.correlationId());
497:             client.send(clientRequest, currentTimeMs);
498:             transactionManager.setInFlightCorrelationId(clientRequest.correlationId());
499:             client.poll(retryBackoffMs, time.milliseconds());
500:             return true;
501:         } catch (IOException e) {
502:             log.debug("Disconnect from {} while trying to send request {}. Going " +
503:                     "to back off and retry.", targetNode, requestBuilder, e);
504:             // We break here so that we pick up the FindCoordinator request immediately.
505:             maybeFindCoordinatorAndRetry(nextRequestHandler);
506:             return true;
507:         }
508:     }
509: 
510:     private void maybeFindCoordinatorAndRetry(TransactionManager.TxnRequestHandler nextRequestHandler) {
511:         if (nextRequestHandler.needsCoordinator()) {
512:             transactionManager.lookupCoordinator(nextRequestHandler);
513:         } else {
514:             // For non-coordinator requests, sleep here to prevent a tight loop when no node is available
515:             time.sleep(retryBackoffMs);
516:             metadata.requestUpdate(false);
517:         }
518: 
519:         transactionManager.retry(nextRequestHandler);
520:     }
521: 
522:     private void maybeAbortBatches(RuntimeException exception) {
523:         if (accumulator.hasIncomplete()) {
524:             log.error("Aborting producer batches due to fatal error", exception);
525:             accumulator.abortBatches(exception);
526:         }
527:     }
528: 
529:     /**
530:      * Start closing the sender (won't actually complete until all data is sent out)
531:      */
532:     public void initiateClose() {
533:         // Ensure accumulator is closed first to guarantee that no more appends are accepted after
534:         // breaking from the sender loop. Otherwise, we may miss some callbacks when shutting down.
535:         this.accumulator.close();
536:         this.running = false;
537:         this.wakeup();
538:     }
539: 
540:     /**
541:      * Closes the sender without sending out any pending messages.
542:      */
543:     public void forceClose() {
544:         this.forceClose = true;
545:         initiateClose();
546:     }
547: 
548:     public boolean isRunning() {
549:         return running;
550:     }
551: 
552:     private boolean awaitNodeReady(Node node, FindCoordinatorRequest.CoordinatorType coordinatorType) throws IOException {
553:         if (NetworkClientUtils.awaitReady(client, node, time, requestTimeoutMs)) {
554:             if (coordinatorType == FindCoordinatorRequest.CoordinatorType.TRANSACTION) {
555:                 // Indicate to the transaction manager that the coordinator is ready, allowing it to check ApiVersions
556:                 // This allows us to bump transactional epochs even if the coordinator is temporarily unavailable at
557:                 // the time when the abortable error is handled
558:                 transactionManager.handleCoordinatorReady();
559:             }
560:             return true;
561:         }
562:         return false;
563:     }
564: 
565:     /**
566:      * Handle a produce response
567:      */
568:     private void handleProduceResponse(ClientResponse response, Map<TopicPartition, ProducerBatch> batches, Map<Uuid, String> topicNames, long now) {
569:         RequestHeader requestHeader = response.requestHeader();
570:         int correlationId = requestHeader.correlationId();
571:         if (response.wasTimedOut()) {
572:             log.trace("Cancelled request with header {} due to the last request to node {} timed out",
573:                 requestHeader, response.destination());
574:             for (ProducerBatch batch : batches.values())
575:                 completeBatch(batch, new ProduceResponse.PartitionResponse(Errors.REQUEST_TIMED_OUT, String.format("Disconnected from node %s due to timeout", response.destination())),
576:                         correlationId, now, null);
577:         } else if (response.wasDisconnected()) {
578:             log.trace("Cancelled request with header {} due to node {} being disconnected",
579:                 requestHeader, response.destination());
580:             for (ProducerBatch batch : batches.values())
581:                 completeBatch(batch, new ProduceResponse.PartitionResponse(Errors.NETWORK_EXCEPTION, String.format("Disconnected from node %s", response.destination())),
582:                         correlationId, now, null);
583:         } else if (response.versionMismatch() != null) {
584:             log.warn("Cancelled request {} due to a version mismatch with node {}",
585:                     response, response.destination(), response.versionMismatch());
586:             for (ProducerBatch batch : batches.values())
587:                 completeBatch(batch, new ProduceResponse.PartitionResponse(Errors.UNSUPPORTED_VERSION), correlationId, now, null);
588:         } else {
589:             log.trace("Received produce response from node {} with correlation id {}", response.destination(), correlationId);
590:             // if we have a response, parse it
591:             if (response.hasResponse()) {
592:                 // Sender should exercise PartitionProduceResponse rather than ProduceResponse.PartitionResponse
593:                 // https://issues.apache.org/jira/browse/KAFKA-10696
594:                 ProduceResponse produceResponse = (ProduceResponse) response.responseBody();
595:                 // This will be set by completeBatch.
596:                 Map<TopicPartition, Metadata.LeaderIdAndEpoch> partitionsWithUpdatedLeaderInfo = new HashMap<>();
597:                 produceResponse.data().responses().forEach(r -> r.partitionResponses().forEach(p -> {
598:                     ProduceResponse.PartitionResponse partResp = new ProduceResponse.PartitionResponse(
599:                             Errors.forCode(p.errorCode()),
600:                             p.baseOffset(),
601:                             p.logAppendTimeMs(),
602:                             p.logStartOffset(),
603:                             p.recordErrors()
604:                                 .stream()
605:                                 .map(e -> new ProduceResponse.RecordError(e.batchIndex(), e.batchIndexErrorMessage()))
606:                                 .collect(Collectors.toList()),
607:                             p.errorMessage(),
608:                             p.currentLeader());
609: 
610:                     // Version 13 drop topic name and add support to topic id.
611:                     // We need to find batch based on topic id and partition index only as
612:                     // topic name in the response will be empty.
613:                     // For older versions, topic id is zero, and we will find the batch based on the topic name.
614:                     TopicPartition tp = (!r.topicId().equals(Uuid.ZERO_UUID) && topicNames.containsKey(r.topicId())) ?
615:                             new TopicPartition(topicNames.get(r.topicId()), p.index()) :
616:                             new TopicPartition(r.name(), p.index());
617: 
618:                     ProducerBatch batch = batches.get(tp);
619:                     if (batch == null) {
620:                         throw new IllegalStateException("Can't find batch created for topic id " + r.topicId() +
621:                                 " topic name " + r.name() + " partition " + p.index() + " using " + topicNames);
622:                     }
623:                     completeBatch(batch, partResp, correlationId, now, partitionsWithUpdatedLeaderInfo);
624:                 }));
625: 
626:                 if (!partitionsWithUpdatedLeaderInfo.isEmpty()) {
627:                     List<Node> leaderNodes = produceResponse.data().nodeEndpoints().stream()
628:                         .map(e -> new Node(e.nodeId(), e.host(), e.port(), e.rack()))
629:                         .filter(e -> !e.equals(Node.noNode()))
630:                         .collect(
631:                             Collectors.toList());
632:                     Set<TopicPartition> updatedPartitions = metadata.updatePartitionLeadership(partitionsWithUpdatedLeaderInfo, leaderNodes);
633:                     if (log.isTraceEnabled()) {
634:                         updatedPartitions.forEach(
635:                             part -> log.debug("For {} leader was updated.", part)
636:                         );
637:                     }
638:                 }
639: 
640:                 this.sensors.recordLatency(response.destination(), response.requestLatencyMs());
641:             } else {
642:                 // this is the acks = 0 case, just complete all requests
643:                 for (ProducerBatch batch : batches.values()) {
644:                     completeBatch(batch, new ProduceResponse.PartitionResponse(Errors.NONE), correlationId, now, null);
645:                 }
646:             }
647:         }
648:     }
649: 
650:     /**
651:      * Complete or retry the given batch of records.
652:      *
653:      * @param batch The record batch
654:      * @param response The produce response
655:      * @param correlationId The correlation id for the request
656:      * @param now The current POSIX timestamp in milliseconds
657:      * @param partitionsWithUpdatedLeaderInfo This will be populated with partitions that have updated leader info.
658:      */
659:     private void completeBatch(ProducerBatch batch, ProduceResponse.PartitionResponse response, long correlationId,
660:                                long now, Map<TopicPartition, Metadata.LeaderIdAndEpoch> partitionsWithUpdatedLeaderInfo) {
661:         Errors error = response.error;
662: 
663:         if (error == Errors.MESSAGE_TOO_LARGE && batch.recordCount > 1 && !batch.isDone() &&
664:                 (batch.magic() >= RecordBatch.MAGIC_VALUE_V2 || batch.isCompressed())) {
665:             // If the batch is too large, we split the batch and send the split batches again. We do not decrement
666:             // the retry attempts in this case.
667:             log.warn(
668:                 "Got error produce response in correlation id {} on topic-partition {}, splitting and retrying ({} attempts left). Error: {}",
669:                 correlationId,
670:                 batch.topicPartition,
671:                 this.retries - batch.attempts(),
672:                 formatErrMsg(response));
673:             if (transactionManager != null)
674:                 transactionManager.removeInFlightBatch(batch);
675:             this.accumulator.splitAndReenqueue(batch);
676:             maybeRemoveAndDeallocateBatch(batch);
677:             this.sensors.recordBatchSplit();
678:         } else if (error != Errors.NONE) {
679:             if (canRetry(batch, response, now)) {
680:                 log.warn(
681:                     "Got error produce response with correlation id {} on topic-partition {}, retrying ({} attempts left). Error: {}",
682:                     correlationId,
683:                     batch.topicPartition,
684:                     this.retries - batch.attempts() - 1,
685:                     formatErrMsg(response));
686:                 reenqueueBatch(batch, now);
687:             } else if (error == Errors.DUPLICATE_SEQUENCE_NUMBER) {
688:                 // If we have received a duplicate sequence error, it means that the sequence number has advanced beyond
689:                 // the sequence of the current batch, and we haven't retained batch metadata on the broker to return
690:                 // the correct offset and timestamp.
691:                 //
692:                 // The only thing we can do is to return success to the user and not return a valid offset and timestamp.
693:                 completeBatch(batch, response);
694:             } else {
695:                 // tell the user the result of their request. We only adjust sequence numbers if the batch didn't exhaust
696:                 // its retries -- if it did, we don't know whether the sequence number was accepted or not, and
697:                 // thus it is not safe to reassign the sequence.
698:                 failBatch(batch, response, batch.attempts() < this.retries);
699:             }
700:             if (error.exception() instanceof InvalidMetadataException) {
701:                 if (error.exception() instanceof UnknownTopicOrPartitionException) {
702:                     log.warn("Received unknown topic or partition error in produce request on partition {}. The " +
703:                             "topic-partition may not exist or the user may not have Describe access to it",
704:                         batch.topicPartition);
705:                 } else {
706:                     log.warn("Received invalid metadata error in produce request on partition {} due to {} Going " +
707:                             "to request metadata update now", batch.topicPartition, error.exception(response.errorMessage).toString());
708:                 }
709:                 if (error.exception() instanceof NotLeaderOrFollowerException || error.exception() instanceof FencedLeaderEpochException) {
710:                     log.debug("For {}, received error {}, with leaderIdAndEpoch {}", batch.topicPartition, error, response.currentLeader);
711:                     if (partitionsWithUpdatedLeaderInfo != null
712:                         && (response.currentLeader.leaderId() != -1 && response.currentLeader.leaderEpoch() != -1)) {
713:                         partitionsWithUpdatedLeaderInfo.put(batch.topicPartition, new Metadata.LeaderIdAndEpoch(
714:                             Optional.of(response.currentLeader.leaderId()), Optional.of(response.currentLeader.leaderEpoch())));
715:                     }
716:                 }
717:                 metadata.requestUpdate(false);
718:             }
719:         } else {
720:             completeBatch(batch, response);
721:         }
722: 
723:         // Unmute the completed partition.
724:         if (guaranteeMessageOrder)
725:             this.accumulator.unmutePartition(batch.topicPartition);
726:     }
727: 
728:     /**
729:      * Format the error from a {@link ProduceResponse.PartitionResponse} in a user-friendly string
730:      * e.g "NETWORK_EXCEPTION. Error Message: Disconnected from node 0"
731:      */
732:     private String formatErrMsg(ProduceResponse.PartitionResponse response) {
733:         String errorMessageSuffix = (response.errorMessage == null || response.errorMessage.isEmpty()) ?
734:                 "" : String.format(". Error Message: %s", response.errorMessage);
735:         return String.format("%s%s", response.error, errorMessageSuffix);
736:     }
