738:     private void reenqueueBatch(ProducerBatch batch, long currentTimeMs) {
739:         this.accumulator.reenqueue(batch, currentTimeMs);
740:         maybeRemoveFromInflightBatches(batch);
741:         this.sensors.recordRetries(batch.topicPartition.topic(), batch.recordCount);
742:     }
