744:     private void completeBatch(ProducerBatch batch, ProduceResponse.PartitionResponse response) {
745:         if (transactionManager != null) {
746:             transactionManager.handleCompletedBatch(batch, response);
747:         }
748: 
749:         if (batch.complete(response.baseOffset, response.logAppendTime)) {
750:             maybeRemoveAndDeallocateBatch(batch);
751:         }
752:     }
