958:             this.metrics = metrics;
959:             this.time = time;
960: 
961:             this.batchSizeSensor = metrics.sensor("batch-size");
962:             this.batchSizeSensor.add(metrics.batchSizeAvg, new Avg());
963:             this.batchSizeSensor.add(metrics.batchSizeMax, new Max());
964: 
965:             this.compressionRateSensor = metrics.sensor("compression-rate");
