967: 
968:             this.queueTimeSensor = metrics.sensor("queue-time");
969:             this.queueTimeSensor.add(metrics.recordQueueTimeAvg, new Avg());
970:             this.queueTimeSensor.add(metrics.recordQueueTimeMax, new Max());
971: 
972:             this.requestTimeSensor = metrics.sensor("request-time");
973:             this.requestTimeSensor.add(metrics.requestLatencyAvg, new Avg());
974:             this.requestTimeSensor.add(metrics.requestLatencyMax, new Max());
975: 
976:             this.recordsPerRequestSensor = metrics.sensor("records-per-request");
977:             this.recordsPerRequestSensor.add(new Meter(metrics.recordSendRate, metrics.recordSendTotal));
978:             this.recordsPerRequestSensor.add(metrics.recordsPerRequestAvg, new Avg());
979: 
980:             this.retrySensor = metrics.sensor("record-retries");
981:             this.retrySensor.add(new Meter(metrics.recordRetryRate, metrics.recordRetryTotal));
982: 
983:             this.errorSensor = metrics.sensor("errors");
984:             this.errorSensor.add(new Meter(metrics.recordErrorRate, metrics.recordErrorTotal));
985: 
986:             this.maxRecordSizeSensor = metrics.sensor("record-size");
987:             this.maxRecordSizeSensor.add(metrics.recordSizeMax, new Max());
988:             this.maxRecordSizeSensor.add(metrics.recordSizeAvg, new Avg());
989: 
990:             this.metrics.addMetric(metrics.requestsInFlight, (config, now) -> client.inFlightRequestCount());
991:             this.metrics.addMetric(metrics.metadataAge,
992:                 (config, now) -> (now - metadata.lastSuccessfulUpdate()) / 1000.0);
993: 
994:             this.batchSplitSensor = metrics.sensor("batch-split-rate");
995:             this.batchSplitSensor.add(new Meter(metrics.batchSplitRate, metrics.batchSplitTotal));
