998:         private void maybeRegisterTopicMetrics(String topic) {
999:             // if one sensor of the metrics has been registered for the topic,
1000:             // then all other sensors should have been registered; and vice versa
1001:             String topicRecordsCountName = "topic." + topic + ".records-per-batch";
1002:             Sensor topicRecordCount = this.metrics.getSensor(topicRecordsCountName);
1003:             if (topicRecordCount == null) {
1004:                 Map<String, String> metricTags = Collections.singletonMap("topic", topic);
1005: 
1006:                 topicRecordCount = this.metrics.sensor(topicRecordsCountName);
1007:                 MetricName rateMetricName = this.metrics.topicRecordSendRate(metricTags);
1008:                 MetricName totalMetricName = this.metrics.topicRecordSendTotal(metricTags);
1009:                 topicRecordCount.add(new Meter(rateMetricName, totalMetricName));
1010: 
1011:                 String topicByteRateName = "topic." + topic + ".bytes";
1012:                 Sensor topicByteRate = this.metrics.sensor(topicByteRateName);
1013:                 rateMetricName = this.metrics.topicByteRate(metricTags);
1014:                 totalMetricName = this.metrics.topicByteTotal(metricTags);
1015:                 topicByteRate.add(new Meter(rateMetricName, totalMetricName));
1016: 
1017:                 String topicCompressionRateName = "topic." + topic + ".compression-rate";
1018:                 Sensor topicCompressionRate = this.metrics.sensor(topicCompressionRateName);
1019:                 MetricName m = this.metrics.topicCompressionRate(metricTags);
1020:                 topicCompressionRate.add(m, new Avg());
1021: 
1022:                 String topicRetryName = "topic." + topic + ".record-retries";
1023:                 Sensor topicRetrySensor = this.metrics.sensor(topicRetryName);
1024:                 rateMetricName = this.metrics.topicRecordRetryRate(metricTags);
1025:                 totalMetricName = this.metrics.topicRecordRetryTotal(metricTags);
1026:                 topicRetrySensor.add(new Meter(rateMetricName, totalMetricName));
1027: 
1028:                 String topicErrorName = "topic." + topic + ".record-errors";
1029:                 Sensor topicErrorSensor = this.metrics.sensor(topicErrorName);
1030:                 rateMetricName = this.metrics.topicRecordErrorRate(metricTags);
1031:                 totalMetricName = this.metrics.topicRecordErrorTotal(metricTags);
1032:                 topicErrorSensor.add(new Meter(rateMetricName, totalMetricName));
1033:             }
1034:         }
