1036:         public void updateProduceRequestMetrics(Map<Integer, List<ProducerBatch>> batches) {
1037:             long now = time.milliseconds();
1038:             for (List<ProducerBatch> nodeBatch : batches.values()) {
1039:                 int records = 0;
1040:                 for (ProducerBatch batch : nodeBatch) {
1041:                     // register all per-topic metrics at once
1042:                     String topic = batch.topicPartition.topic();
1043:                     maybeRegisterTopicMetrics(topic);
1044: 
1045:                     // per-topic record send rate
1046:                     String topicRecordsCountName = "topic." + topic + ".records-per-batch";
1047:                     Sensor topicRecordCount = Objects.requireNonNull(this.metrics.getSensor(topicRecordsCountName));
1048:                     topicRecordCount.record(batch.recordCount);
1049: 
1050:                     // per-topic bytes send rate
1051:                     String topicByteRateName = "topic." + topic + ".bytes";
1052:                     Sensor topicByteRate = Objects.requireNonNull(this.metrics.getSensor(topicByteRateName));
1053:                     topicByteRate.record(batch.estimatedSizeInBytes());
1054: 
1055:                     // per-topic compression rate
1056:                     String topicCompressionRateName = "topic." + topic + ".compression-rate";
1057:                     Sensor topicCompressionRate = Objects.requireNonNull(this.metrics.getSensor(topicCompressionRateName));
1058:                     topicCompressionRate.record(batch.compressionRatio());
1059: 
1060:                     // global metrics
1061:                     this.batchSizeSensor.record(batch.estimatedSizeInBytes(), now);
1062:                     this.queueTimeSensor.record(batch.queueTimeMs(), now);
1063:                     this.compressionRateSensor.record(batch.compressionRatio());
1064:                     this.maxRecordSizeSensor.record(batch.maxRecordSize, now);
1065:                     records += batch.recordCount;
1066:                 }
1067:                 this.recordsPerRequestSensor.record(records, now);
1068:             }
1069:         }
