55: /**
56:  * A batch of records that is or will be sent.
57:  *
58:  * This class is not thread safe and external synchronization must be used when modifying it
59:  */
60: public final class ProducerBatch {
61: 
62:     private static final Logger log = LoggerFactory.getLogger(ProducerBatch.class);
63: 
64:     private enum FinalState { ABORTED, FAILED, SUCCEEDED }
65: 
66:     final long createdMs;
67:     final TopicPartition topicPartition;
68:     final ProduceRequestResult produceFuture;
69: 
70:     private final List<Thunk> thunks = new ArrayList<>();
71:     private final MemoryRecordsBuilder recordsBuilder;
72:     private final AtomicInteger attempts = new AtomicInteger(0);
73:     private final boolean isSplitBatch;
