144:     public FutureRecordMetadata tryAppend(long timestamp, byte[] key, byte[] value, Header[] headers, Callback callback, long now) {
145:         if (!recordsBuilder.hasRoomFor(timestamp, key, value, headers)) {
146:             return null;
