205:      * @return `true` if the batch has been completed, `false` otherwise.
206:      */
207:     public boolean isDone() {
208:         return finalState() != null;
209:     }
210: 
211:     /**
212:      * Complete the batch successfully.
213:      * @param baseOffset The base offset of the messages assigned by the server
214:      * @param logAppendTime The log append time or -1 if CreateTime is being used
215:      * @return true if the batch was completed as a result of this call, and false
216:      *   if it had been completed previously
217:      */
218:     public boolean complete(long baseOffset, long logAppendTime) {
219:         return done(baseOffset, logAppendTime, null, null);
220:     }
221: 
222:     /**
223:      * Complete the batch exceptionally. The provided top-level exception will be used
224:      * for each record future contained in the batch.
225:      *
226:      * @param topLevelException top-level partition error
227:      * @param recordExceptions Record exception function mapping batchIndex to the respective record exception
228:      * @return true if the batch was completed as a result of this call, and false
229:      *   if it had been completed previously
230:      */
231:     public boolean completeExceptionally(
232:         RuntimeException topLevelException,
233:         Function<Integer, RuntimeException> recordExceptions
234:     ) {
235:         Objects.requireNonNull(topLevelException);
236:         Objects.requireNonNull(recordExceptions);
237:         return done(ProduceResponse.INVALID_OFFSET, RecordBatch.NO_TIMESTAMP, topLevelException, recordExceptions);
238:     }
