240:     /**
241:      * Finalize the state of a batch. Final state, once set, is immutable. This function may be called
242:      * once or twice on a batch. It may be called twice if
243:      * 1. An inflight batch expires before a response from the broker is received. The batch's final
244:      * state is set to FAILED. But it could succeed on the broker and second time around batch.done() may
245:      * try to set SUCCEEDED final state.
246:      * 2. If a transaction abortion happens or if the producer is closed forcefully, the final state is
247:      * ABORTED but again it could succeed if broker responds with a success.
248:      *
249:      * Attempted transitions from [FAILED | ABORTED] --> SUCCEEDED are logged.
250:      * Attempted transitions from one failure state to the same or a different failed state are ignored.
251:      * Attempted transitions from SUCCEEDED to the same or a failed state throw an exception.
252:      *
253:      * @param baseOffset The base offset of the messages assigned by the server
254:      * @param logAppendTime The log append time or -1 if CreateTime is being used
255:      * @param topLevelException The exception that occurred (or null if the request was successful)
256:      * @param recordExceptions Record exception function mapping batchIndex to the respective record exception
257:      * @return true if the batch was completed successfully and false if the batch was previously aborted
258:      */
259:     private boolean done(
260:         long baseOffset,
261:         long logAppendTime,
262:         RuntimeException topLevelException,
263:         Function<Integer, RuntimeException> recordExceptions
264:     ) {
265:         final FinalState tryFinalState = (topLevelException == null) ? FinalState.SUCCEEDED : FinalState.FAILED;
266:         if (tryFinalState == FinalState.SUCCEEDED) {
267:             log.trace("Successfully produced messages to {} with base offset {}.", topicPartition, baseOffset);
268:         } else {
269:             log.trace("Failed to produce messages to {} with base offset {}.", topicPartition, baseOffset, topLevelException);
270:         }
271: 
272:         if (this.finalState.compareAndSet(null, tryFinalState)) {
273:             completeFutureAndFireCallbacks(baseOffset, logAppendTime, recordExceptions);
274:             return true;
275:         }
276: 
277:         if (this.finalState.get() != FinalState.SUCCEEDED) {
278:             if (tryFinalState == FinalState.SUCCEEDED) {
279:                 // Log if a previously unsuccessful batch succeeded later on.
280:                 log.debug("ProduceResponse returned {} for {} after batch with base offset {} had already been {}.",
281:                     tryFinalState, topicPartition, baseOffset, this.finalState.get());
282:             } else {
283:                 // FAILED --> FAILED and ABORTED --> FAILED transitions are ignored.
284:                 log.debug("Ignored state transition {} -> {} for {} batch with base offset {}",
285:                     this.finalState.get(), tryFinalState, topicPartition, baseOffset);
286:             }
287:         } else {
288:             // A SUCCESSFUL batch must not attempt another state change.
289:             throw new IllegalStateException("A " + this.finalState.get() + " batch must not attempt another state change to " + tryFinalState);
290:         }
291:         return false;
292:     }
