348:     private Deque<ProducerBatch> splitRecordsIntoBatches(RecordBatch recordBatch, int splitBatchSize) {
349:         Deque<ProducerBatch> batches = new ArrayDeque<>();
350:         Iterator<Thunk> thunkIter = thunks.iterator();
351:         // We always allocate batch size because we are already splitting a big batch.
352:         // And we also Retain the create time of the original batch.
353:         ProducerBatch batch = null;
354: 
355:         for (Record record : recordBatch) {
356:             assert thunkIter.hasNext();
357:             Thunk thunk = thunkIter.next();
358:             if (batch == null)
359:                 batch = createBatchOffAccumulatorForRecord(record, splitBatchSize);
360: 
361:             // A newly created batch can always host the first message.
362:             if (!batch.tryAppendForSplit(record.timestamp(), record.key(), record.value(), record.headers(), thunk)) {
363:                 batches.add(batch);
364:                 batch.closeForRecordAppends();
365:                 batch = createBatchOffAccumulatorForRecord(record, splitBatchSize);
366:                 batch.tryAppendForSplit(record.timestamp(), record.key(), record.value(), record.headers(), thunk);
367:             }
368:         }
369: 
370:         // Close the last batch and add it to the batch list after split.
371:         if (batch != null) {
372:             batches.add(batch);
373:             batch.closeForRecordAppends();
374:         }
375: 
376:         return batches;
377:     }
