379:     private void finalizeSplitBatches(Deque<ProducerBatch> batches) {
380:         // Chain all split batch ProduceRequestResults to the original batch's produceFuture
381:         // Ensures the original batch's future doesn't complete until all split batches complete
382:         for (ProducerBatch splitBatch : batches) {
383:             produceFuture.addDependent(splitBatch.produceFuture);
384:         }
