404:         int initialSize = Math.max(AbstractRecords.estimateSizeInBytesUpperBound(magic(),
405:                 recordsBuilder.compression().type(), record.key(), record.value(), record.headers()), batchSize);
406:         ByteBuffer buffer = ByteBuffer.allocate(initialSize);
